// Replace + add to back stack (so Back returns to the previous fragment)
supportFragmentManager.commit {
  setReorderingAllowed(true)
  replace(R.id.container, DetailFragment())
  addToBackStack("detail")   // tag lets you pop back to a specific state
}

// Pop the back stack (like Back button)
supportFragmentManager.popBackStack()

// The MODERN way (2020+): the Navigation component handles all of this
findNavController().navigate(R.id.action_home_to_detail)

// File: MainActivity.kt (with two fragments and shared data via ViewModel)
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.LinearLayout
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import androidx.fragment.app.Fragment
import androidx.fragment.app.activityViewModels
import androidx.fragment.app.commit
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel

// 1. Shared ViewModel — the modern way for fragments to communicate
class NameVM : ViewModel() {
  val name = MutableLiveData("")
}

// 2. Fragment that lets the user type a name
class InputFragment : Fragment() {
  private val vm: NameVM by activityViewModels()   // SAME instance as the Activity

  override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, s: Bundle?): View {
    val layout = LinearLayout(requireContext()).apply { orientation = LinearLayout.VERTICAL }
    val et = android.widget.EditText(requireContext()).apply { hint = "Enter name" }
    val btn = Button(requireContext()).apply { text = "Submit" }
    layout.addView(et); layout.addView(btn)

    btn.setOnClickListener { vm.name.value = et.text.toString() }
    return layout
  }
}

// 3. Fragment that shows the current name
class DisplayFragment : Fragment() {
  private val vm: NameVM by activityViewModels()

  override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, s: Bundle?): View {
    val tv = TextView(requireContext()).apply { text = "(no name)" }

    // Use viewLifecycleOwner — NOT `this` — for observers so they unsubscribe
    // when the VIEW is destroyed, not just when the fragment is destroyed.
    vm.name.observe(viewLifecycleOwner) { tv.text = "Hello, $it!" }

    return tv
  }
}

class MainActivity : AppCompatActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)

    val root = LinearLayout(this).apply { orientation = LinearLayout.VERTICAL }
    val topContainer = android.widget.FrameLayout(this).apply { id = View.generateViewId() }
    val bottomContainer = android.widget.FrameLayout(this).apply { id = View.generateViewId() }
    root.addView(topContainer); root.addView(bottomContainer)
    setContentView(root)

    // Add both fragments — they share the SAME ViewModel via activityViewModels()
    if (savedInstanceState == null) {
      supportFragmentManager.commit {
        add(topContainer.id, InputFragment(), "input")
        add(bottomContainer.id, DisplayFragment(), "display")
      }
    }
  }
}

// User types → InputFragment updates vm.name → DisplayFragment observes and rerenders.
// This is exactly how modern fragment communication works: shared ViewModel + LiveData/Flow.
// The bad old way was fragment-to-fragment interfaces or the Activity as a middleman.
